export function rateLimitMiddleware(
  maxOverride?: number
): MiddlewareHandler<{ Bindings: Env }> {
  return async (c, next) => {
    const ip      = c.req.header("CF-Connecting-IP") ?? "unknown";
    const path    = new URL(c.req.url).pathname.replace(/\//g, "_");
