export async function assignRole(
  env: Env,
  orgId: string,
  assignerUserId: string,
  assignerRole: Role,
  targetUserId: string,
  newRole: Role
): Promise<void> {
  if (!canAssignRole(assignerRole, newRole)) {
    throw Object.assign(
      new Error(`Your role '${assignerRole}' cannot assign '${newRole}'.`),
      { status: 403 }
    );
  }

  const targetUser = await getUserById(env.DB, targetUserId);
