         strftime('%Y-%m', date) as period,
         SUM(CASE WHEN amount > 0 THEN amount ELSE 0 END)        as revenue,
         SUM(CASE WHEN amount < 0 THEN ABS(amount) ELSE 0 END)   as expenses
       FROM transactions
