  const current = await cacheGet<Record<string, unknown>>(c.env.CACHE, key) ?? {};
  const updated = { ...current, ...body };
  await cacheSet(c.env.CACHE, key, updated, 60 * 60 * 24 * 30);
  return c.json({ ok: true,  updated });
});

